using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCESS" : "FAILED") + " ===\n");

// Collect all errors
var errors = new List<(string project, string code, string file, int line, int col, string message, string subcategory)>();
var warnings = new List<(string project, string code, string file, int line, int col, string message)>();

void Visit(BaseNode node, string currentProject)
{
    if (node is Project p)
        currentProject = System.IO.Path.GetFileName(p.ProjectFile ?? "") ;
    if (node is Microsoft.Build.Logging.StructuredLogger.Error e)
    {
        errors.Add((currentProject, e.Code ?? "", e.File ?? "", e.LineNumber, e.ColumnNumber, e.Text ?? "", e.Subcategory ?? ""));
    }
    if (node is Microsoft.Build.Logging.StructuredLogger.Warning w)
    {
        warnings.Add((currentProject, w.Code ?? "", w.File ?? "", w.LineNumber, w.ColumnNumber, w.Text ?? ""));
    }
    if (node is TreeNode tn)
    {
        foreach (var child in tn.Children)
        {
            if (child is BaseNode bn)
                Visit(bn, currentProject);
        }
    }
}

Visit(build, "");

Console.WriteLine("=== ERRORS (" + errors.Count + ") ===");
foreach (var e in errors)
{
    Console.WriteLine($"[{e.project}] {e.code}: {e.file}({e.line},{e.col}): {e.message}");
}

Console.WriteLine("\n=== WARNINGS (" + warnings.Count + ") ===");
foreach (var w in warnings)
{
    Console.WriteLine($"[{w.project}] {w.code}: {w.file}({w.line},{w.col}): {w.message}");
}

// Also look for project build results
Console.WriteLine("\n=== PROJECT BUILD RESULTS ===");
void VisitProjects(BaseNode node)
{
    if (node is Project proj)
    {
        Console.WriteLine($"  {System.IO.Path.GetFileName(proj.ProjectFile ?? "?")} -> {(proj.Succeeded ? "OK" : "FAILED")}");
    }
    if (node is TreeNode tn2)
    {
        foreach (var child in tn2.Children)
        {
            if (child is BaseNode bn)
                VisitProjects(bn);
        }
    }
}
VisitProjects(build);
