foreach (var g in byProject)
{
    Console.WriteLine($"\n  {g.Key}: {g.Count()} error(s)");
    foreach (var e in g)
        Console.WriteLine($"    {e.code} at {Path.GetFileName(e.file)}:{e.line} - {e.message}");
}

// Check dependencies
Console.WriteLine("\n=== DEPENDENCY CHAIN ===");
Console.WriteLine("  Core (no dependencies)");
Console.WriteLine("  Services -> Core");
Console.WriteLine("  Api -> Services, Core");

