var projectsWithOwnErrors = byProject.Select(g => g.Key).ToHashSet();
Console.WriteLine("\n=== ROOT CAUSE ANALYSIS ===");
Console.WriteLine($"  Projects with direct errors: {string.Join(", ", projectsWithOwnErrors)}");

