    Console.WriteLine("  Core.csproj: No compilation errors of its own (check project-level issues)");
if (!projectsWithOwnErrors.Contains("Api.csproj"))
    Console.WriteLine("  Api.csproj: No compilation errors of its own - failure is CASCADING from Services.csproj");

