Console.WriteLine("\n=== SEARCHING FOR SOURCE CONTENT IN BINLOG ===");
void SearchNodes(BaseNode node, int depth, string path)
{
    var nodeName = node.ToString() ?? "";
    if (depth < 6 && (nodeName.Contains("UserService") || nodeName.Contains("Models.cs") || nodeName.Contains("Program.cs")))
